// ===== CV DOWNLOAD WINDOW =====
// Note: CV_B64 is embedded base64 PDF

export function buildCVDownload(body) {

  body.classList.add('silver');
  const CV_B64   = 'data:application/pdf;base64,';
  const PORT_B64 = 'data:application/pdf;base64,';
  body.innerHTML = `
    <div style="padding:20px;display:flex;flex-direction:column;gap:0;height:100%;">

      <!-- Header -->
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:18px;padding:10px 12px;background:#fff;border:1px solid #d4d0c8;">
        <span style="font-size:32px;">📄</span>
        <div>
          <div style="font-size:12px;font-weight:700;color:#0a246a;">Maksim Manojlovic — Documents</div>
          <div style="font-size:10px;color:#666;">Click a file to download. Both files are ready to save.</div>
        </div>
      </div>

      <!-- CV row -->
      <div style="display:flex;align-items:center;gap:12px;padding:12px;background:#fff;border:1px solid #d4d0c8;margin-bottom:8px;cursor:pointer;"
        onclick="downloadFile('CV_Maksim_Manojlovic.pdf', '${CV_B64}')"
        onmouseover="this.style.background='#dde8f8'" onmouseout="this.style.background='#fff'">
        <span style="font-size:36px;flex-shrink:0;">📋</span>
        <div style="flex:1;">
          <div style="font-size:12px;font-weight:700;color:#000;">CV_Maksim_Manojlovic.pdf</div>
          <div style="font-size:10px;color:#666;margin-top:2px;">Resume / Curriculum Vitae · 156 KB</div>
          <div style="font-size:10px;color:#888;">Education, Work Experience, Tech Stack</div>
        </div>
        <div style="padding:4px 14px;background:#d4d0c8;border:2px solid;border-color:#fff #888 #888 #fff;font-size:11px;white-space:nowrap;">
          ⬇ Download
        </div>
      </div>

      <!-- Portfolio row -->
      <div style="display:flex;align-items:center;gap:12px;padding:12px;background:#fff;border:1px solid #d4d0c8;margin-bottom:16px;cursor:pointer;"
        onclick="downloadFile('Portfolio_Maksim_Manojlovic.pdf', '${PORT_B64}')"
        onmouseover="this.style.background='#dde8f8'" onmouseout="this.style.background='#fff'">
        <span style="font-size:36px;flex-shrink:0;">🗂️</span>
        <div style="flex:1;">
          <div style="font-size:12px;font-weight:700;color:#000;">Portfolio_Maksim_Manojlovic.pdf</div>
          <div style="font-size:10px;color:#666;margin-top:2px;">Portfolio / Project List · 116 KB</div>
          <div style="font-size:10px;color:#888;">Completed projects with links & descriptions</div>
        </div>
        <div style="padding:4px 14px;background:#d4d0c8;border:2px solid;border-color:#fff #888 #888 #fff;font-size:11px;white-space:nowrap;">
          ⬇ Download
        </div>
      </div>

      <div style="font-size:10px;color:#888;text-align:center;">
        💡 Files download directly — no server needed. Last updated: 2025
      </div>
    </div>`;
}
export function downloadFile(filename, dataUri) {
  const a = document.createElement('a');
  a.href = dataUri;
  a.download = filename;
  a.click();
  window.showNotification('Downloading...', filename + '\nSaving to your Downloads folder.');
}

import { state } from '../state.js';
export function registerCVDownload() {
  state.windowDefs['cv-download'] = {
    title: 'Download CV — Maksim Manojlovic', icon: '📄', w: 460, h: 320,
    menuBar: ['File','Tools','Help'], toolbar: false, statusBar: false,
    content: buildCVDownload
  };
}
